import React,{useState} from 'react'


export function useForm(initialFValues){
    const [values,setValues] = useState(initialFValues)


    const handleInputChagne = e => {
        const {name,value} = e.target 

        setValues({
            ...values,
            [name]: value
        })
    }


    return {
        values,
        setValues,
        handleInputChagne
    }
}
